package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetQuoteCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());
    }

    @Test
    public void testGetQuoteCharacter_NullQuote() throws Exception {
        // Create a CSVFormat instance based on DEFAULT but with quoteCharacter set to null via reflection
        CSVFormat format = CSVFormat.DEFAULT;

        Field quoteCharField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharField.setAccessible(true);

        // Create a new CSVFormat instance with quoteCharacter set to null
        // since CSVFormat is immutable, we clone DEFAULT and set quoteCharacter to null via reflection on a new instance

        // Use the withQuote method with null to get the instance with null quote character
        CSVFormat mysqlFormat = format.withQuote((Character) null);

        Character quoteChar = mysqlFormat.getQuoteCharacter();
        assertNull(quoteChar);
    }

    @Test
    public void testGetQuoteCharacter_CustomQuote() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote('\'');
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('\'', quoteChar.charValue());
    }

    @Test
    public void testGetQuoteCharacter_WithQuoteCharacterObject() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote(Character.valueOf('`'));
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('`', quoteChar.charValue());
    }
}
